# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for managing users, projects, tasks,
messaging, performance dashboards, and reporting.

Implemented with the Python standard library only and kept ASCII-clean.
The original brief described a "PhotoCollabEditor"; the accompanying test
suite exercises a generic team-collaboration domain model, which is what
this module provides.  ``PhotoCollabEditor`` is exposed at the bottom of the
module as an alias of :class:`TeamCollaborationManager` so either name may be
used.

Design highlights
-----------------
* A single shared re-entrant lock guards every mutation, so the manager is
  safe to use from multiple threads.  All sub-services expose that same lock
  object (``_lock``) to make the shared-state contract explicit.
* Identifiers are globally unique across every entity type and start at 1.
* Every public getter returns a deep copy so callers can never mutate the
  internal store by accident.
"""

import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Roles a user may hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kinds of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by this module."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
class Attachment(object):
    """A file attached to a message."""

    def __init__(self, id, filename, size, uploaded_by, uploaded_at):
        self.id = id
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at

    def __repr__(self):
        return "Attachment(id={0!r}, filename={1!r}, size={2!r})".format(
            self.id, self.filename, self.size
        )


class User(object):
    """A member of the collaboration platform."""

    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at

    def __repr__(self):
        return "User(id={0!r}, username={1!r}, role={2!r})".format(
            self.id, self.username, self.role
        )


class Project(object):
    """A unit of work owned by a user and containing tasks."""

    def __init__(self, id, name, description, start_date, end_date, owner_id,
                 created_at):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.created_at = created_at

    def __repr__(self):
        return "Project(id={0!r}, name={1!r}, owner_id={2!r})".format(
            self.id, self.name, self.owner_id
        )


class Task(object):
    """A single piece of work inside a project."""

    def __init__(self, id, project_id, title, assignee_id, deadline,
                 created_at):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.status = TaskStatus.NOT_STARTED
        self.started_at = None
        self.completed_at = None
        self.created_at = created_at

    def __repr__(self):
        return "Task(id={0!r}, title={1!r}, status={2!r})".format(
            self.id, self.title, self.status
        )


class Message(object):
    """A comment or piece of feedback attached to a project or task."""

    def __init__(self, id, author_id, body, project_id, task_id, parent_id,
                 created_at):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = []
        self.created_at = created_at
        self.edited_at = None

    def __repr__(self):
        return "Message(id={0!r}, author_id={1!r})".format(
            self.id, self.author_id
        )


class Rating(object):
    """Feedback one user gives another."""

    def __init__(self, id, rater_id, ratee_id, score, feedback, task_id,
                 created_at):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at

    def __repr__(self):
        return "Rating(id={0!r}, ratee_id={1!r}, score={2!r})".format(
            self.id, self.ratee_id, self.score
        )


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------
def _clone(obj):
    """Return a deep copy so callers cannot mutate the internal store."""

    return copy.deepcopy(obj)


def _require(mapping, key, label):
    """Fetch ``key`` from ``mapping`` or raise :class:`NotFoundError`."""

    value = mapping.get(key)
    if value is None:
        raise NotFoundError("{0} with id {1} was not found".format(label, key))
    return value


def _normalize_text(value, label):
    """Validate that ``value`` is a non-empty string and return it trimmed."""

    if not isinstance(value, str):
        raise ValidationError("{0} must be a string".format(label))
    trimmed = value.strip()
    if not trimmed:
        raise ValidationError("{0} must not be empty".format(label))
    return trimmed


def _validate_email(email):
    """Validate a minimal email shape and return the trimmed value."""

    if not isinstance(email, str):
        raise ValidationError("email must be a string")
    trimmed = email.strip()
    if not trimmed:
        raise ValidationError("email must not be empty")
    parts = trimmed.split("@")
    if len(parts) != 2 or not parts[0].strip() or not parts[1].strip():
        raise ValidationError("email is not valid: {0!r}".format(email))
    return trimmed


def _validate_role(role):
    if not isinstance(role, UserRole):
        raise ValidationError("role must be a UserRole, got {0!r}".format(role))
    return role


def _validate_status(status):
    if not isinstance(status, TaskStatus):
        raise ValidationError(
            "status must be a TaskStatus, got {0!r}".format(status)
        )
    return status


def _duration_seconds(task):
    """Completion duration in seconds, or ``None`` if not measurable."""

    if (
        task.status == TaskStatus.COMPLETED
        and task.started_at is not None
        and task.completed_at is not None
    ):
        return (task.completed_at - task.started_at).total_seconds()
    return None


# ---------------------------------------------------------------------------
# Shared store
# ---------------------------------------------------------------------------
class _Store(object):
    """Holds every piece of mutable state plus shared coordination objects."""

    def __init__(self, now):
        self.lock = threading.RLock()
        self._now = now
        self._id_counter = 0

        # Primary entity tables keyed by id.
        self.users = {}
        self.projects = {}
        self.tasks = {}
        self.messages = {}
        self.ratings = {}

        # Secondary indexes.
        self.username_to_id = {}
        self.email_to_id = {}
        self.project_tasks = {}      # project_id -> [task_id, ...]
        self.assignee_tasks = {}     # user_id -> [task_id, ...]
        self.project_messages = {}   # project_id -> [message_id, ...]
        self.task_messages = {}      # task_id -> [message_id, ...]
        self.ratee_ratings = {}      # user_id -> [rating_id, ...]

    def next_id(self):
        self._id_counter += 1
        return self._id_counter

    def now(self):
        return self._now()


class _Service(object):
    """Base for every sub-service; shares the store and its lock."""

    def __init__(self, store):
        self._store = store
        self._lock = store.lock


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class UserService(_Service):
    def register(self, username, email, role=UserRole.MEMBER):
        username = _normalize_text(username, "username")
        email = _validate_email(email)
        _validate_role(role)
        store = self._store
        with self._lock:
            if username in store.username_to_id:
                raise DuplicateError(
                    "username already in use: {0!r}".format(username)
                )
            if email in store.email_to_id:
                raise DuplicateError(
                    "email already in use: {0!r}".format(email)
                )
            user = User(
                store.next_id(), username, email, role, store.now()
            )
            store.users[user.id] = user
            store.username_to_id[username] = user.id
            store.email_to_id[email] = user.id
            return _clone(user)

    def get(self, user_id):
        with self._lock:
            return _clone(_require(self._store.users, user_id, "User"))

    def list(self):
        with self._lock:
            users = sorted(self._store.users.values(), key=lambda u: u.id)
            return [_clone(u) for u in users]

    def update(self, user_id, username=None, email=None, role=None):
        store = self._store
        with self._lock:
            user = _require(store.users, user_id, "User")

            new_username = None
            if username is not None:
                new_username = _normalize_text(username, "username")
                owner = store.username_to_id.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "username already in use: {0!r}".format(new_username)
                    )

            new_email = None
            if email is not None:
                new_email = _validate_email(email)
                owner = store.email_to_id.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "email already in use: {0!r}".format(new_email)
                    )

            if role is not None:
                _validate_role(role)

            if new_username is not None:
                store.username_to_id.pop(user.username, None)
                user.username = new_username
                store.username_to_id[new_username] = user_id
            if new_email is not None:
                store.email_to_id.pop(user.email, None)
                user.email = new_email
                store.email_to_id[new_email] = user_id
            if role is not None:
                user.role = role
            return _clone(user)

    def delete(self, user_id):
        store = self._store
        with self._lock:
            user = _require(store.users, user_id, "User")

            for project in store.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user owns project {0} and cannot be deleted".format(
                            project.id
                        )
                    )

            for task_id in store.assignee_tasks.get(user_id, []):
                task = store.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "user has open task {0} and cannot be deleted".format(
                            task_id
                        )
                    )

            store.username_to_id.pop(user.username, None)
            store.email_to_id.pop(user.email, None)
            store.assignee_tasks.pop(user_id, None)
            store.ratee_ratings.pop(user_id, None)
            del store.users[user_id]


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class ProjectService(_Service):
    def create(self, name, start_date, end_date, owner_id, description=""):
        name = _normalize_text(name, "project name")
        if description is None:
            description = ""
        store = self._store
        with self._lock:
            _require(store.users, owner_id, "User")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            project = Project(
                store.next_id(), name, description, start_date, end_date,
                owner_id, store.now()
            )
            store.projects[project.id] = project
            store.project_tasks[project.id] = []
            store.project_messages[project.id] = []
            return _clone(project)

    def get(self, project_id):
        with self._lock:
            return _clone(_require(self._store.projects, project_id, "Project"))

    def list(self):
        with self._lock:
            projects = sorted(
                self._store.projects.values(), key=lambda p: p.id
            )
            return [_clone(p) for p in projects]

    def update(self, project_id, name=None, start_date=None, end_date=None,
               description=None):
        store = self._store
        with self._lock:
            project = _require(store.projects, project_id, "Project")

            new_name = None
            if name is not None:
                new_name = _normalize_text(name, "project name")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if new_name is not None:
                project.name = new_name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _clone(project)

    def delete(self, project_id):
        store = self._store
        with self._lock:
            _require(store.projects, project_id, "Project")

            for task_id in list(store.project_tasks.get(project_id, [])):
                task = store.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    self._remove_from_index(
                        store.assignee_tasks, task.assignee_id, task_id
                    )
                for message_id in list(store.task_messages.get(task_id, [])):
                    store.messages.pop(message_id, None)
                store.task_messages.pop(task_id, None)
            store.project_tasks.pop(project_id, None)

            for message_id in list(store.project_messages.get(project_id, [])):
                store.messages.pop(message_id, None)
            store.project_messages.pop(project_id, None)

            del store.projects[project_id]

    @staticmethod
    def _remove_from_index(index, key, value):
        bucket = index.get(key)
        if bucket and value in bucket:
            bucket.remove(value)


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class TaskService(_Service):
    def create(self, project_id, title, assignee_id=None, deadline=None):
        title = _normalize_text(title, "task title")
        store = self._store
        with self._lock:
            project = _require(store.projects, project_id, "Project")
            if assignee_id is not None:
                _require(store.users, assignee_id, "User")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError(
                    "deadline must not precede the project start date"
                )
            task = Task(
                store.next_id(), project_id, title, assignee_id, deadline,
                store.now()
            )
            store.tasks[task.id] = task
            store.project_tasks.setdefault(project_id, []).append(task.id)
            if assignee_id is not None:
                store.assignee_tasks.setdefault(assignee_id, []).append(task.id)
            return _clone(task)

    def get(self, task_id):
        with self._lock:
            return _clone(_require(self._store.tasks, task_id, "Task"))

    def list_by_project(self, project_id):
        store = self._store
        with self._lock:
            _require(store.projects, project_id, "Project")
            task_ids = store.project_tasks.get(project_id, [])
            tasks = sorted(
                (store.tasks[t] for t in task_ids), key=lambda t: t.id
            )
            return [_clone(t) for t in tasks]

    def list_by_assignee(self, assignee_id):
        store = self._store
        with self._lock:
            _require(store.users, assignee_id, "User")
            task_ids = store.assignee_tasks.get(assignee_id, [])
            tasks = sorted(
                (store.tasks[t] for t in task_ids), key=lambda t: t.id
            )
            return [_clone(t) for t in tasks]

    def assign(self, task_id, assignee_id):
        store = self._store
        with self._lock:
            task = _require(store.tasks, task_id, "Task")
            _require(store.users, assignee_id, "User")
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign(self, task_id, new_assignee_id):
        store = self._store
        with self._lock:
            task = _require(store.tasks, task_id, "Task")
            _require(store.users, new_assignee_id, "User")
            self._set_assignee(task, new_assignee_id)
            return _clone(task)

    def unassign(self, task_id):
        store = self._store
        with self._lock:
            task = _require(store.tasks, task_id, "Task")
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        store = self._store
        with self._lock:
            task = _require(store.tasks, task_id, "Task")
            if deadline is not None:
                project = store.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not precede the project start date"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        _validate_status(status)
        store = self._store
        with self._lock:
            task = _require(store.tasks, task_id, "Task")
            now = store.now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return _clone(task)

    def _set_assignee(self, task, new_assignee_id):
        store = self._store
        if task.assignee_id == new_assignee_id:
            return
        if task.assignee_id is not None:
            bucket = store.assignee_tasks.get(task.assignee_id)
            if bucket and task.id in bucket:
                bucket.remove(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            store.assignee_tasks.setdefault(new_assignee_id, []).append(task.id)


# ---------------------------------------------------------------------------
# Message service
# ---------------------------------------------------------------------------
class MessageService(_Service):
    def post(self, author_id, body, project_id=None, task_id=None,
             parent_id=None, attachments=None):
        store = self._store
        with self._lock:
            _require(store.users, author_id, "User")

            if project_id is None and task_id is None:
                raise ValidationError(
                    "a message must target a project or a task"
                )
            if project_id is not None and task_id is not None:
                raise ValidationError(
                    "a message may target a project or a task, not both"
                )
            if project_id is not None:
                _require(store.projects, project_id, "Project")
            if task_id is not None:
                _require(store.tasks, task_id, "Task")
            if parent_id is not None:
                _require(store.messages, parent_id, "Message")

            body = body if body is not None else ""
            has_attachments = bool(attachments)
            if not body.strip() and not has_attachments:
                raise ValidationError(
                    "a message must have a body or at least one attachment"
                )

            message = Message(
                store.next_id(), author_id, body, project_id, task_id,
                parent_id, store.now()
            )
            if has_attachments:
                for filename, data in attachments:
                    message.attachments.append(
                        self._build_attachment(author_id, filename, data)
                    )

            store.messages[message.id] = message
            if project_id is not None:
                store.project_messages.setdefault(project_id, []).append(
                    message.id
                )
            else:
                store.task_messages.setdefault(task_id, []).append(message.id)
            return _clone(message)

    def edit(self, message_id, editor_id, new_body):
        store = self._store
        with self._lock:
            message = _require(store.messages, message_id, "Message")
            if message.author_id != editor_id:
                raise AuthorizationError(
                    "only the author may edit this message"
                )
            new_body = new_body if new_body is not None else ""
            if not new_body.strip() and not message.attachments:
                raise ValidationError("message body must not be empty")
            message.body = new_body
            message.edited_at = store.now()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        store = self._store
        with self._lock:
            message = _require(store.messages, message_id, "Message")
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach files to this message"
                )
            attachment = self._build_attachment(uploader_id, filename, data)
            message.attachments.append(attachment)
            return _clone(message)

    def list_by_project(self, project_id):
        store = self._store
        with self._lock:
            _require(store.projects, project_id, "Project")
            ids = store.project_messages.get(project_id, [])
            messages = sorted(
                (store.messages[m] for m in ids), key=lambda m: m.id
            )
            return [_clone(m) for m in messages]

    def list_by_task(self, task_id):
        store = self._store
        with self._lock:
            _require(store.tasks, task_id, "Task")
            ids = store.task_messages.get(task_id, [])
            messages = sorted(
                (store.messages[m] for m in ids), key=lambda m: m.id
            )
            return [_clone(m) for m in messages]

    def delete(self, message_id, requester_id):
        store = self._store
        with self._lock:
            message = _require(store.messages, message_id, "Message")
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete this message"
                )
            if message.project_id is not None:
                bucket = store.project_messages.get(message.project_id)
                if bucket and message_id in bucket:
                    bucket.remove(message_id)
            if message.task_id is not None:
                bucket = store.task_messages.get(message.task_id)
                if bucket and message_id in bucket:
                    bucket.remove(message_id)
            del store.messages[message_id]

    def _build_attachment(self, uploader_id, filename, data):
        filename = _normalize_text(filename, "filename")
        if data is None:
            data = b""
        try:
            size = len(data)
        except TypeError:
            raise ValidationError("attachment data must be sized")
        return Attachment(
            self._store.next_id(), filename, size, uploader_id,
            self._store.now()
        )


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class PerformanceService(_Service):
    def completion_rate(self, user_id):
        store = self._store
        with self._lock:
            _require(store.users, user_id, "User")
            return self._completion_rate(user_id)

    def average_completion_time(self, user_id):
        store = self._store
        with self._lock:
            _require(store.users, user_id, "User")
            return self._average_completion_time(user_id)

    def submit_rating(self, rater_id, ratee_id, score, feedback=None,
                      task_id=None):
        store = self._store
        if not isinstance(score, int) or isinstance(score, bool):
            raise ValidationError("score must be an integer")
        if score < 1 or score > 5:
            raise ValidationError("score must be between 1 and 5")
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            _require(store.users, rater_id, "User")
            _require(store.users, ratee_id, "User")
            if task_id is not None:
                _require(store.tasks, task_id, "Task")
            rating = Rating(
                store.next_id(), rater_id, ratee_id, score, feedback, task_id,
                store.now()
            )
            store.ratings[rating.id] = rating
            store.ratee_ratings.setdefault(ratee_id, []).append(rating.id)
            return _clone(rating)

    def ratings_summary(self, user_id):
        store = self._store
        with self._lock:
            _require(store.users, user_id, "User")
            return self._ratings_summary(user_id)

    def user_dashboard(self, user_id):
        store = self._store
        with self._lock:
            _require(store.users, user_id, "User")
            task_ids = store.assignee_tasks.get(user_id, [])
            total = len(task_ids)
            completed = 0
            in_progress = 0
            not_started = 0
            for task_id in task_ids:
                status = store.tasks[task_id].status
                if status == TaskStatus.COMPLETED:
                    completed += 1
                elif status == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                else:
                    not_started += 1
            summary = self._ratings_summary(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(user_id),
                "average_completion_time": self._average_completion_time(
                    user_id
                ),
                "rating_count": summary["count"],
                "rating_average": summary["average"],
            }

    # -- internal, lock already held -------------------------------------
    def _completion_rate(self, user_id):
        task_ids = self._store.assignee_tasks.get(user_id, [])
        if not task_ids:
            return 0.0
        completed = sum(
            1
            for task_id in task_ids
            if self._store.tasks[task_id].status == TaskStatus.COMPLETED
        )
        return completed / float(len(task_ids))

    def _average_completion_time(self, user_id):
        durations = []
        for task_id in self._store.assignee_tasks.get(user_id, []):
            seconds = _duration_seconds(self._store.tasks[task_id])
            if seconds is not None:
                durations.append(seconds)
        if not durations:
            return None
        return sum(durations) / float(len(durations))

    def _ratings_summary(self, user_id):
        rating_ids = self._store.ratee_ratings.get(user_id, [])
        ratings = [self._store.ratings[r] for r in rating_ids]
        if not ratings:
            return {"count": 0, "average": 0.0, "ratings": []}
        scores = [r.score for r in ratings]
        average = sum(scores) / float(len(scores))
        return {
            "count": len(ratings),
            "average": average,
            "ratings": [_clone(r) for r in ratings],
        }


