# Report service
# ---------------------------------------------------------------------------
class ReportService(_Service):
    def __init__(self, store, performance):
        super(ReportService, self).__init__(store)
        self._performance = performance

    def project_progress(self, project_id):
        store = self._store
        with self._lock:
            project = _require(store.projects, project_id, "Project")
            now = store.now()
            task_ids = store.project_tasks.get(project_id, [])
            tasks = [store.tasks[t] for t in task_ids]

            status_counts = {status.value: 0 for status in TaskStatus}
            completed = 0
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.status != TaskStatus.COMPLETED
                    and task.deadline is not None
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            total = len(tasks)
            completion_rate = completed / float(total) if total else 0.0
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance(self, project_id=None):
        store = self._store
        with self._lock:
            if project_id is not None:
                _require(store.projects, project_id, "Project")
                scope = [
                    store.tasks[t]
                    for t in store.project_tasks.get(project_id, [])
                ]
            else:
                scope = list(store.tasks.values())

            grouped = {}
            for task in scope:
                if task.assignee_id is None:
                    continue
                grouped.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(grouped):
                tasks = grouped[user_id]
                total = len(tasks)
                completed = sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                )
                durations = [
                    _duration_seconds(t)
                    for t in tasks
                    if _duration_seconds(t) is not None
                ]
                average_time = (
                    sum(durations) / float(len(durations))
                    if durations
                    else None
                )
                summary = self._performance._ratings_summary(user_id)
                user = store.users.get(user_id)
                rows.append({
                    "user_id": user_id,
                    "username": user.username if user else None,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": (
                        completed / float(total) if total else 0.0
                    ),
                    "average_completion_time": average_time,
                    "rating_count": summary["count"],
                    "rating_average": summary["average"],
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance(self, user_id):
        store = self._store
        with self._lock:
            user = _require(store.users, user_id, "User")
            task_ids = store.assignee_tasks.get(user_id, [])
            tasks = sorted(
                (store.tasks[t] for t in task_ids), key=lambda t: t.id
            )
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = [
                _duration_seconds(t)
                for t in tasks
                if _duration_seconds(t) is not None
            ]
            average_time = (
                sum(durations) / float(len(durations)) if durations else None
            )
            summary = self._performance._ratings_summary(user_id)
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "deadline": t.deadline,
                    "completion_seconds": _duration_seconds(t),
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (
                    completed / float(total) if total else 0.0
                ),
                "average_completion_time": average_time,
                "rating_count": summary["count"],
                "rating_average": summary["average"],
                "tasks": task_rows,
            }

    # -- export ----------------------------------------------------------
    def export(self, report, fmt):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError(
                "fmt must be a ReportFormat, got {0!r}".format(fmt)
            )
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if fmt == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    def _to_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            columns = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time", "rating_count",
                "rating_average",
            ]
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([row.get(column, "") for column in columns])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(
                ["task_id", "title", "status", "project_id",
                 "completion_seconds"]
            )
            for task in report.get("tasks", []):
                writer.writerow([
                    task.get("task_id", ""),
                    task.get("title", ""),
                    task.get("status", ""),
                    task.get("project_id", ""),
                    task.get("completion_seconds", ""),
                ])
        else:
            writer.writerow(["metric", "value"])
            for key, value in report.items():
                if isinstance(value, (dict, list)):
                    continue
                writer.writerow([key, value])
        return output.getvalue()

    def _to_pdf(self, report):
        return _build_pdf(self._report_to_lines(report))

    @staticmethod
    def _report_to_lines(report):
        lines = ["Team Collaboration Report"]
        report_type = report.get("report_type", "report")
        lines.append("Type: {0}".format(report_type))
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines


# ---------------------------------------------------------------------------
# Minimal PDF generation (standard library only)
# ---------------------------------------------------------------------------
def _pdf_escape(text):
    text = str(text)
    text = text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
    text = text.replace("\r", " ").replace("\n", " ")
    return "".join(ch if 32 <= ord(ch) < 127 else "?" for ch in text)


def _build_pdf(text_lines):
    """Assemble a minimal but valid single-page PDF document."""

    if not text_lines:
        text_lines = [""]

    content_ops = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    first = True
    for line in text_lines:
        escaped = _pdf_escape(line)
        if first:
            content_ops.append("({0}) Tj".format(escaped))
            first = False
        else:
            content_ops.append("T*")
            content_ops.append("({0}) Tj".format(escaped))
    content_ops.append("ET")
    content = "\n".join(content_ops).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        ),
        (
            b"<< /Length " + str(len(content)).encode("ascii") + b" >>\n"
            b"stream\n" + content + b"\nendstream"
        ),
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray()
    pdf += b"%PDF-1.4\n"
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(index).encode("ascii")
        pdf += body
        pdf += b"\nendobj\n"

    xref_position = len(pdf)
    count = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(count).encode("ascii")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n"
    pdf += "<< /Size {0} /Root 1 0 R >>\n".format(count).encode("ascii")
    pdf += b"startxref\n"
    pdf += "{0}\n".format(xref_position).encode("ascii")
    pdf += b"%%EOF"
    return bytes(pdf)


