# ---------------------------------------------------------------------------
class TeamCollaborationManager(object):
    """Thread-safe facade coordinating every sub-service.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the current
        :class:`datetime.datetime`.  Injecting a clock makes time-dependent
        behaviour deterministic in tests.  Defaults to ``datetime.now``.
    """

    def __init__(self, now=None):
        if now is None:
            now = datetime.now
        store = _Store(now)
        self._store = store
        self._lock = store.lock

        self.users = UserService(store)
        self.projects = ProjectService(store)
        self.tasks = TaskService(store)
        self.messages = MessageService(store)
        self.performance = PerformanceService(store)
        self.reports = ReportService(store, self.performance)

    # -- users -----------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
